INSERT INTO `question_groups` (`group_id`, `quiz_id`, `assign_id`, `title`, `passage_text`, `image_url`, `audio_url`, `instructions`, `order_num`, `mock_test_id`) VALUES
(1, 1, NULL, 'Listening Section 1', NULL, NULL, NULL, 'Section 1: orientation desk conversation and room changes.', 1, NULL),
(2, 1, NULL, 'Listening Section 2', NULL, NULL, NULL, 'Section 2: volunteer fair registration details.', 2, NULL),
(3, 1, NULL, 'Listening Section 3', NULL, NULL, NULL, 'Section 3: library workshop advice for new researchers.', 3, NULL),
(4, 1, NULL, 'Listening Section 4', NULL, NULL, NULL, 'Section 4: museum lecture about rivers and urban planning.', 4, NULL),
(5, 2, NULL, 'Reading Passage 1', 'A group of public schools in Singapore turned unused rooftops into gardens where students grow vegetables, measure rainfall, and record insect activity. Teachers reported that practical observation improved participation in science lessons and created more teamwork across grades.', NULL, NULL, 'Passage 1: read the article and answer questions 1 to 13.', 1, NULL),
(6, 2, NULL, 'Reading Passage 2', 'A medium-sized city expanded its protected bike lane network over five years. The project included new lighting, better road markings, and discount parking for bicycles near transit stations. Researchers tracked changes in daily commuting habits and retail activity near the routes.', NULL, NULL, 'Passage 2: focus on purpose, evidence, and implication.', 2, NULL),
(7, 2, NULL, 'Reading Passage 3', 'Marine biologists in Indonesia tested low-cost coral frames made from recycled metal and local stone. The project compared coral growth, fish return, and volunteer maintenance across several coastal villages. The results showed that community monitoring mattered as much as the material used.', NULL, NULL, 'Passage 3: identify the writer view, details, and conclusions.', 3, NULL),
(8, 3, NULL, 'Writing Task 2', 'Some city governments are considering strict limits on private cars in downtown areas.', NULL, NULL, 'Write an essay discussing whether this is a positive or negative development.', 1, NULL),
(9, 4, NULL, 'Part 5 - Incomplete Sentences', NULL, NULL, NULL, 'Choose the option that best completes each business sentence.', 1, NULL),
(10, 5, NULL, 'Reading Set 1', 'Email from workshop coordinator Maya Tran confirming a writing workshop schedule, room change, and material checklist for participants.', NULL, NULL, 'Questions 1 to 6 refer to the email from the workshop coordinator.', 1, NULL),
(11, 5, NULL, 'Reading Set 2', 'Hotel notice explaining breakfast hours, luggage storage limits, and maintenance work on the elevator during one weekend.', NULL, NULL, 'Questions 7 to 12 refer to the hotel notice.', 2, NULL),
(12, 5, NULL, 'Reading Set 3', 'Memo from a shipping team about delayed containers, revised delivery dates, and customer updates that must be sent before noon.', NULL, NULL, 'Questions 13 to 18 refer to the internal shipping memo.', 3, NULL),
(13, 5, NULL, 'Reading Set 4', 'Staff schedule for a retail branch showing revised shifts, a stock count session, and weekend cashier coverage.', NULL, NULL, 'Questions 19 to 24 refer to the staff schedule.', 4, NULL),
(14, 5, NULL, 'Reading Set 5', 'Summary of a customer satisfaction survey comparing waiting time, service attitude, and digital payment experience across three stores.', NULL, NULL, 'Questions 25 to 30 refer to the survey summary.', 5, NULL),
(15, 5, NULL, 'Reading Set 6', 'Product brochure for a compact printer aimed at small offices, highlighting wireless setup, toner savings, and service support.', NULL, NULL, 'Questions 31 to 36 refer to the product brochure.', 6, NULL),
(16, 5, NULL, 'Reading Set 7', 'Email chain about an invoice follow-up, missing line items, and the revised payment deadline after the supplier corrected the document.', NULL, NULL, 'Questions 37 to 42 refer to the invoice follow-up email chain.', 7, NULL),
(17, 5, NULL, 'Reading Set 8', 'Travel itinerary for a regional sales trip that includes a flight change, hotel confirmation, and a note about client meeting times.', NULL, NULL, 'Questions 43 to 48 refer to the travel itinerary.', 8, NULL),
(18, 5, NULL, 'Reading Set 9', 'Community event announcement for a weekend street market with vendor setup rules, a rain backup plan, and social media promotion tasks.', NULL, NULL, 'Questions 49 to 54 refer to the event announcement.', 9, NULL),
(19, NULL, NULL, 'Listening', NULL, NULL, NULL, 'Full test listening section: notes, directions, class discussions, and a short lecture.', 1, 1),
(20, NULL, NULL, 'Reading Passage 1', 'Several school districts tested free breakfast programs before the first lesson. Attendance improved modestly, but the largest gains were seen among students who previously arrived late or skipped morning classes. Administrators later studied how queue design and menu variety changed participation.', NULL, NULL, 'Questions 41 to 53 refer to Reading Passage 1.', 2, 1),
(21, NULL, NULL, 'Reading Passage 2', 'Urban planners compared small neighborhood parks with large destination parks in terms of walking distance, family use, and long-term maintenance costs. The report found that frequent, short visits often mattered more than the total size of the site.', NULL, NULL, 'Questions 54 to 66 refer to Reading Passage 2.', 3, 1),
(22, NULL, NULL, 'Reading Passage 3', 'A water reuse project supplied treated greywater to public gardens and industrial cooling systems. Engineers had to explain safety standards clearly because residents were unsure how the system worked. Trust improved when usage data was published every month.', NULL, NULL, 'Questions 67 to 80 refer to Reading Passage 3.', 4, 1),
(23, NULL, NULL, 'Writing Task 1', 'The chart shows how employees in Metro City traveled to work in 2018 and 2025, comparing private cars, buses, bicycles, and rail.', NULL, NULL, 'Summarize the main features and make comparisons where relevant.', 5, 1),
(24, NULL, NULL, 'Writing Task 2', 'Some people believe governments should invest more in public transport than in new roads for private vehicles.', NULL, NULL, 'Discuss both views and give your own opinion.', 6, 1),
(25, NULL, NULL, 'Listening', NULL, NULL, NULL, 'Full test listening section: health campaign notes, student planning, interview advice, and an environmental lecture.', 1, 2),
(26, NULL, NULL, 'Reading Passage 1', 'Sleep researchers studied students who switched from late-night revision to shorter but regular review sessions. The project measured memory retention, mood, and error rates in timed reading tasks. The results challenged the idea that long study hours are always more effective.', NULL, NULL, 'Questions 41 to 53 refer to Reading Passage 1.', 2, 2),
(27, NULL, NULL, 'Reading Passage 2', 'One coastal town reduced single-use plastic by changing market rules, supporting refill shops, and training vendors to explain the changes to tourists. Early resistance softened after shop owners saw that customers adapted quickly when alternatives were clearly displayed.', NULL, NULL, 'Questions 54 to 66 refer to Reading Passage 2.', 3, 2),
(28, NULL, NULL, 'Reading Passage 3', 'Museum educators redesigned exhibits so visitors could compare objects, test small ideas, and leave short reflections. Attendance did not rise sharply at first, but repeat visits increased because families felt they could explore the displays at different levels.', NULL, NULL, 'Questions 67 to 80 refer to Reading Passage 3.', 4, 2),
(29, NULL, NULL, 'Writing Task 1', 'The graph compares weekly library visits by teenagers, university students, adults, and retired residents between 2019 and 2024.', NULL, NULL, 'Summarize the information by selecting and reporting the main features.', 5, 2),
(30, NULL, NULL, 'Writing Task 2', 'Many companies now allow staff to work from home several days each week.', NULL, NULL, 'Do the advantages of this arrangement outweigh the disadvantages?', 6, 2),
(31, NULL, NULL, 'Part 1 - Photographs', NULL, NULL, NULL, 'Look at each photograph and choose the best description.', 1, 3),
(32, NULL, NULL, 'Part 2 - Question Response', NULL, NULL, NULL, 'Listen to the question and choose the best response.', 2, 3),
(33, NULL, NULL, 'Part 3 - Conversations', NULL, NULL, NULL, 'Each short business conversation is followed by three questions.', 3, 3),
(34, NULL, NULL, 'Part 4 - Short Talks', NULL, NULL, NULL, 'Each short talk is followed by three questions.', 4, 3),
(35, NULL, NULL, 'Part 5 - Incomplete Sentences', NULL, NULL, NULL, 'Select the best word or phrase to complete each sentence.', 5, 3),
(36, NULL, NULL, 'Part 6 - Text Completion', 'An internal company newsletter draft discusses a delayed software rollout, a revised support schedule, and several training sessions for staff in different branches.', NULL, NULL, 'Choose the best option to complete each blank in the text set.', 6, 3),
(37, NULL, NULL, 'Part 7 - Reading Comprehension', 'This full reading section includes notices, email chains, reports, schedules, and short product information for operational teams.', NULL, NULL, 'Read the documents and answer the questions that follow.', 7, 3),
(38, NULL, NULL, 'Part 1 - Photographs', NULL, NULL, NULL, 'Look at each photograph and choose the best description.', 1, 4),
(39, NULL, NULL, 'Part 2 - Question Response', NULL, NULL, NULL, 'Listen to the question and choose the best response.', 2, 4),
(40, NULL, NULL, 'Part 3 - Conversations', NULL, NULL, NULL, 'Each project conversation is followed by three questions.', 3, 4),
(41, NULL, NULL, 'Part 4 - Short Talks', NULL, NULL, NULL, 'Each training talk is followed by three questions.', 4, 4),
(42, NULL, NULL, 'Part 5 - Incomplete Sentences', NULL, NULL, NULL, 'Select the best word or phrase to complete each sentence.', 5, 4),
(43, NULL, NULL, 'Part 6 - Text Completion', 'A policy update for branch managers explains a new visitor sign-in process, revised equipment booking rules, and where to send monthly compliance reports.', NULL, NULL, 'Choose the best option to complete each blank in the text set.', 6, 4),
(44, NULL, NULL, 'Part 7 - Reading Comprehension', 'This reading section features procurement emails, event notices, policy reminders, travel forms, and a customer satisfaction report.', NULL, NULL, 'Read the documents and answer the questions that follow.', 7, 4),
(45, NULL, NULL, 'Listening', NULL, NULL, NULL, 'Weekend simulation listening section with practical notes, campus services, and a short lecture.', 1, 5),
(46, NULL, NULL, 'Reading Passage 1', 'A cycling-friendly city introduced smaller interventions such as protected junctions, neighborhood maps, and school safety campaigns before funding large infrastructure projects. Transport researchers were interested in whether modest changes could still shift daily habits.', NULL, NULL, 'Questions 41 to 53 refer to Reading Passage 1.', 2, 5),
(47, NULL, NULL, 'Reading Passage 2', 'Wetland restoration near a crowded suburb improved flood control and also created new walking routes for residents. Local volunteers helped remove invasive plants, monitor bird activity, and explain the project to visitors during the rainy season.', NULL, NULL, 'Questions 54 to 66 refer to Reading Passage 2.', 3, 5),
(48, NULL, NULL, 'Reading Passage 3', 'Food historians examined how railway expansion changed eating habits in different regions, especially which goods became common in urban markets and how menus adapted to faster travel times. They argued that transport history shaped more than trade alone.', NULL, NULL, 'Questions 67 to 80 refer to Reading Passage 3.', 4, 5),
(49, NULL, NULL, 'Writing Task 1', 'The bar chart compares household energy use for lighting, cooling, cooking, and devices in 2015 and 2025.', NULL, NULL, 'Summarize the key trends and compare the two years.', 5, 5),
(50, NULL, NULL, 'Writing Task 2', 'Many people think that children spend too much time looking at screens and not enough time doing outdoor activities.', NULL, NULL, 'To what extent do you agree or disagree?', 6, 5);
INSERT INTO `quizzes` (`quiz_id`, `title`, `quiz_type`, `exam_type`, `exam_part`, `passage_text`, `audio_url`, `instructions`, `time_limit`) VALUES
(1, 'IELTS Listening Check - Orientation Week', 'mcq', 'IELTS', 'Listening', NULL, NULL, 'Listen to each section carefully and choose the best answer. Questions move from practical details to short academic information.', 30),
(2, 'IELTS Reading Practice - Community and Environment', 'mcq', 'IELTS', 'Reading', NULL, NULL, 'Read the three passages and answer all forty questions. Pay attention to paraphrase and inference.', 60),
(3, 'IELTS Writing Task 2 - Urban Policy Essay', 'writing', 'IELTS', 'Writing_Task2', NULL, NULL, 'Write at least 250 words. Present a clear position and support it with specific reasons or examples.', 40),
(4, 'TOEIC Part 5 Review - Office Grammar and Vocabulary', 'mcq', 'TOEIC', 'Part5', NULL, NULL, 'Choose the best answer to complete each sentence in a business or office context.', 20),
(5, 'TOEIC Part 7 Reading Sets - Workplace Communication', 'mcq', 'TOEIC', 'Part7', NULL, NULL, 'Read each text set and answer the questions that follow. Use both explicit details and implied meaning.', 55);
