INSERT INTO `schedules` (`schedule_id`, `class_id`, `title`, `description`, `study_date`, `start_time`, `end_time`, `location`) VALUES
(1, 1, 'Buổi 1 - Classroom English and orientation', 'Giới thiệu lộ trình lớp, cách dùng ngôn ngữ trong lớp học, và hoạt động làm quen về mục tiêu học IELTS.', '2026-07-09', '08:00:00', '10:00:00', 'Phòng A1 - NewSkyEnglish'),
(2, 1, 'Buổi 2 - Daily routines and question forms', 'Luyện nói về thói quen hằng ngày, đặt câu hỏi ngắn và sửa lỗi phát âm cơ bản.', '2026-07-11', '08:00:00', '10:00:00', 'Phòng A1 - NewSkyEnglish'),
(3, 2, 'Buổi 1 - Grammar review and connectors', 'Ôn tập thì hiện tại, quá khứ và các từ nối đối lập, bổ sung ví dụ theo chủ đề học tập.', '2026-07-10', '18:00:00', '20:00:00', 'Phòng B2 - NewSkyEnglish'),
(4, 2, 'Buổi 2 - Paragraph building workshop', 'Xây dựng đoạn văn ngắn từ ý chính, câu hỗ trợ và ví dụ đơn giản.', '2026-07-13', '18:00:00', '20:00:00', 'Phòng B2 - NewSkyEnglish'),
(5, 5, 'Buổi 1 - Task 2 opinion essay structure', 'Phân tích đề opinion essay, cách viết thesis statement và topic sentence rõ ràng.', '2026-07-15', '08:00:00', '10:00:00', 'Phòng A5 - NewSkyEnglish'),
(6, 5, 'Buổi 2 - Supporting ideas and examples', 'Luyện mở rộng ý bằng ví dụ thực tế và cách kiểm soát tính mạch lạc của bài viết.', '2026-07-18', '08:00:00', '10:00:00', 'Phòng A5 - NewSkyEnglish'),
(7, 7, 'Buổi 1 - Diagnostic mock test review', 'Chữa đề đầu vào, chỉ ra các lỗi phổ biến ở listening và reading.', '2026-07-19', '08:00:00', '10:00:00', 'Phòng C7 - NewSkyEnglish'),
(8, 7, 'Buổi 2 - Listening distractor workshop', 'Phân tích các bẫy thường gặp và kỹ thuật ghi chú nhanh khi nghe.', '2026-07-22', '08:00:00', '10:00:00', 'Phòng C7 - NewSkyEnglish'),
(9, 8, 'Buổi 1 - Band 6.5 speaking fluency', 'Luyện nói mở rộng ý, dùng từ nối tự nhiên và giữ mạch trả lời lâu hơn.', '2026-07-21', '18:00:00', '20:00:00', 'Phòng D8 - NewSkyEnglish'),
(10, 8, 'Buổi 2 - Reading inference practice', 'Giải thích cách tìm bằng chứng gián tiếp và trả lời câu hỏi suy luận trong passage khó.', '2026-07-24', '18:00:00', '20:00:00', 'Phòng D8 - NewSkyEnglish'),
(11, 21, 'Buổi 1 - Foundation reset and vocabulary', 'Khởi động lớp buổi tối với từ vựng mô tả người, nơi chốn và thói quen.', '2026-07-23', '08:30:00', '10:30:00', 'Phòng A21 - NewSkyEnglish'),
(12, 21, 'Buổi 2 - Listening for key details', 'Nghe thông tin ngắn và nhận diện ngày giờ, địa điểm, giá tiền.', '2026-07-26', '08:30:00', '10:30:00', 'Phòng A21 - NewSkyEnglish'),
(13, 22, 'Buổi 1 - TOEIC grammar baseline check', 'Kiểm tra nền tảng Part 5, các loại từ và cấu trúc câu công sở thông dụng.', '2026-07-25', '18:30:00', '20:30:00', 'Phòng B22 - NewSkyEnglish'),
(14, 22, 'Buổi 2 - Finance and office vocabulary', 'Mở rộng vốn từ về hóa đơn, lịch họp, báo cáo và quy trình làm việc.', '2026-07-28', '18:30:00', '20:30:00', 'Phòng B22 - NewSkyEnglish'),
(15, 24, 'Buổi 1 - Greeting customers naturally', 'Thực hành chào hỏi khách hàng, giới thiệu bản thân và phản hồi lịch sự trong tình huống dịch vụ.', '2026-07-27', '18:30:00', '20:30:00', 'Phòng D24 - NewSkyEnglish'),
(16, 24, 'Buổi 2 - Asking follow-up questions', 'Luyện mẫu câu hỏi tiếp nối và phản xạ giao tiếp trong hội thoại ngắn.', '2026-07-30', '18:30:00', '20:30:00', 'Phòng D24 - NewSkyEnglish'),
(17, 15, 'Buổi 1 - Full test strategy briefing', 'Giới thiệu cách phân bổ thời gian cho từng part trong đề TOEIC mô phỏng.', '2026-04-06', '08:30:00', '10:30:00', 'Phòng C15 - NewSkyEnglish'),
(18, 15, 'Buổi 2 - Answer review and timing control', 'Chữa đề đầu tiên và rèn tốc độ đọc câu hỏi trước khi nghe.', '2026-04-09', '08:30:00', '10:30:00', 'Phòng C15 - NewSkyEnglish'),
(19, 16, 'Buổi 1 - High score reading review', 'Phân tích các câu khó ở Part 7, đặc biệt là email chain và thông báo nội bộ.', '2026-04-12', '18:30:00', '20:30:00', 'Phòng D16 - NewSkyEnglish'),
(20, 16, 'Buổi 2 - Accuracy under time pressure', 'Luyện hoàn thành đề trong thời gian giới hạn và kiểm soát lỗi cuối bài.', '2026-04-15', '18:30:00', '20:30:00', 'Phòng D16 - NewSkyEnglish');
